   141→func (s SortableRuleSlice) Swap(i, j int) { s[i], s[j] = s[j], s[i] }
   142→func (s SortableRuleSlice) Less(i, j int) bool {
   143→	return strings.Compare(s[i].String(), s[j].String()) < 0
